def verify(output: str):
    # Check length
    if len(output) != 700:
        return (False, 0.0, f"String length is {len(output)}, expected 700")

    # Count digits
    digit_counts = {str(d): 0 for d in range(10)}
    for ch in output:
        if ch not in '0123456789':
            return (False, 0.0, f"Invalid character '{ch}' found")
        digit_counts[ch] += 1

    # Constraint 1: The number of digit 8 is prime.
    count_8 = digit_counts['8']
    is_prime = lambda n: n >= 2 and all(n % i != 0 for i in range(2, int(n**0.5) + 1))
    constraint_1 = is_prime(count_8)

    # Constraint 2: The number of digit 3 is exactly 3× the number of digit 6.
    count_3 = digit_counts['3']
    count_6 = digit_counts['6']
    constraint_2 = (count_3 == 3 * count_6)

    # Constraint 3: The number of digit 4 is a multiple of 8.
    count_4 = digit_counts['4']
    constraint_3 = (count_4 % 8 == 0)

    # Constraint 4: The total number of even digits (0,2,4,6,8) is exactly 400.
    even_digits = ['0', '2', '4', '6', '8']
    total_even = sum(digit_counts[d] for d in even_digits)
    constraint_4 = (total_even == 400)

    # Constraint 5: The string contains exactly 12 occurrences of substring "2026" (non-overlapping).
    # We need to count non-overlapping occurrences of "2026"
    count_2026 = 0
    i = 0
    while i <= len(output) - 4:
        if output[i:i+4] == "2026":
            count_2026 += 1
            i += 4  # move past this occurrence to avoid overlapping
        else:
            i += 1

    constraint_5 = (count_2026 == 12)

    # Constraint 6: The string contains no occurrence of "000".
    constraint_6 = ("000" not in output)

    # Constraint 7: The string must not start with 0 and must end with an odd digit.
    starts_with_zero = (output[0] == '0')
    ends_with_odd = (output[-1] in '13579')
    constraint_7 = (not starts_with_zero and ends_with_odd)

    # Constraint 8: Every digit has to appear at least 7 times.
    constraint_8 = all(count >= 7 for count in digit_counts.values())

    # Count satisfied constraints
    constraints = [
        constraint_1, constraint_2, constraint_3, constraint_4,
        constraint_5, constraint_6, constraint_7, constraint_8
    ]
    total_constraints = len(constraints)
    satisfied_count = sum(constraints)
    score = satisfied_count / total_constraints

    # Determine validity and build message
    if all(constraints):
        return (True, 1.0, "All constraints satisfied")

    failed_constraints = []
    if not constraint_1:
        failed_constraints.append(f"count of '8' ({count_8}) is not prime")
    if not constraint_2:
        failed_constraints.append(f"count of '3' ({count_3}) != 3 * count of '6' ({count_6})")
    if not constraint_3:
        failed_constraints.append(f"count of '4' ({count_4}) is not divisible by 8")
    if not constraint_4:
        failed_constraints.append(f"total even digits ({total_even}) != 400")
    if not constraint_5:
        failed_constraints.append(f"count of '2026' ({count_2026}) != 12")
    if not constraint_6:
        failed_constraints.append("contains '000'")
    if not constraint_7:
        if output[0] == '0' and output[-1] not in '13579':
            failed_constraints.append("starts with '0' and does not end with odd digit")
        elif output[0] == '0':
            failed_constraints.append("starts with '0'")
        else:
            failed_constraints.append(f"does not end with odd digit (ends with '{output[-1]}')")
    if not constraint_8:
        min_digit = min(digit_counts.items(), key=lambda x: x[1])
        failed_constraints.append(f"digit '{min_digit[0]}' appears only {min_digit[1]} times (min required: 7)")

    message = f"Failed constraints: {', '.join(failed_constraints)}"
    return (False, score, message)
